solution_code:
#include <iostream>
#include <utility>

int main()
{
    int n{};
    std::cin >> n;

    int arr[20]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    for (int start{ 0 }; start < n - 1; ++start)
    {
        int minIndex{ start };
        for (int cur{ start + 1 }; cur < n; ++cur)
        {
            if (arr[cur] < arr[minIndex])
                minIndex = cur;
        }
        std::swap(arr[start], arr[minIndex]);
    }

    for (int i{ 0 }; i < n; ++i)
        std::cout << arr[i] << ' ';

    return 0;
}

