#include <iostream>
#include <string>
#include <utility>
#include <vector>

struct Student
{
    std::string name{};
    int score{};
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Student> students(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> students[i].name >> students[i].score;

    for (int start{ 0 }; start < n - 1; ++start)
    {
        int maxIndex{ start };
        for (int cur{ start + 1 }; cur < n; ++cur)
        {
            if (students[cur].score > students[maxIndex].score)
                maxIndex = cur;
        }
        std::swap(students[start], students[maxIndex]);
    }

    for (int i{ 0 }; i < n; ++i)
        std::cout << students[i].name << ' ' << students[i].score << '\n';

    return 0;
}
